const swiper3 = new Swiper('.swiper-type-3', {
  direction: 'horizontal',
  loop: true,
  autoplay: {
    delay: 3000,
    disableOnInteraction: true,
  },
  pagination: {
    el: '.pagination-3',
    clickable: true,
  },
  navigation: {
    nextEl: '.btn-next-3',
    prevEl: '.btn-prev-3',
  },
});

css:
/* Swiper Type 03 Styles */
.swiper-type-3 {
  width: 100%;
  border-radius: 20px;
  overflow: hidden;
}

.gradient-7 { background: linear-gradient(135deg, #ff4e50 0%, #f9d423 100%); }
.gradient-8 { background: linear-gradient(135deg, #2c3e50 0%, #3498db 100%); }
.gradient-9 { background: linear-gradient(135deg, #ec008c 0%, #fc6767 100%); }

.control-center {
  display: flex;
  align-items: center;
  gap: 12px;
}
